const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};

if (headers['x-gpmd-secret'] !== $env.GPMD_WEBHOOK_SECRET) {
  return [{ json: { ok: 'false', error: 'Unauthorized' } }];
}

const phone = (body.phone || '').replace(/\D/g, '');
const eleccion = (body.eleccion || '').toLowerCase();

// Parsear elección: puede ser 'am 21', 'pm 22', 'martes am', '21 am', etc.
let fecha = null, franja = null;
const franjas = { am:'AM', pm:'PM', mañana:'AM', tarde:'PM' };
const dias = { '21':'2026-07-21','22':'2026-07-22','23':'2026-07-23','24':'2026-07-24',
  martes:'2026-07-21', miercoles:'2026-07-22', miércoles:'2026-07-22',
  jueves:'2026-07-23', viernes:'2026-07-24' };

for (const [k,v] of Object.entries(dias)) { if (eleccion.includes(k)) { fecha = v; break; } }
for (const [k,v] of Object.entries(franjas)) { if (eleccion.includes(k)) { franja = v; break; } }

// También puede venir fecha/franja directamente
if (!fecha && body.fecha) fecha = body.fecha;
if (!franja && body.franja) franja = (body.franja || '').toUpperCase();

if (!phone || !fecha || !franja) {
  return [{ json: { ok: 'false', error: 'No pude entender la fecha y franja. Por favor indica el día (21, 22, 23 o 24) y la franja (AM o PM).' } }];
}

return [{ json: { phone, fecha, franja } }];

const slot = $('Reservar Slot').first().json;
const parsed = $('Parsear Elección').first().json;

if (!slot || !slot.id) {
  return [{ json: { ok: 'false', error: 'No hay slots disponibles en esa franja. Por favor elige otro horario.' } }];
}

const labels = {
  '2026-07-21':'martes 21','2026-07-22':'miércoles 22',
  '2026-07-23':'jueves 23','2026-07-24':'viernes 24',
};
const fechaStr = typeof slot.fecha === 'string' ? slot.fecha.slice(0,10) : new Date(slot.fecha).toISOString().slice(0,10);

return [{ json: {
  ok: 'true',
  fecha: fechaStr,
  franja: slot.franja,
  hora_inicio: slot.hora_inicio,
  hora_fin: slot.hora_fin,
  resumen: `Tu turno quedó confirmado para el ${labels[fechaStr] || fechaStr} de julio, franja ${slot.franja} (${slot.hora_inicio} – ${slot.hora_fin}).`,
} }];
